  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum UserRole {\n  USER\n  ADMIN\n}\n\nenum SubscriptionStatus {\n  ACTIVE\n  CANCELLED\n  EXPIRED\n  PENDING\n}\n\nenum SubscriptionPlan {\n  MONTHLY\n  YEARLY\n}\n\nenum DrawStatus {\n  UPCOMING\n  ACTIVE\n  COMPLETED\n}\n\nenum WinnerStatus {\n  PENDING_VERIFICATION\n  VERIFIED\n  REJECTED\n  PAID\n}\n\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  firstName String\n  lastName  String\n  phone     String?\n  role      UserRole @default(USER)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  subscription    Subscription?\n  scores          Score[]\n  entries         DrawEntry[]\n  winners         Winner[]\n  selectedCharity UserCharity?\n\n  stripeCustomerId String? @unique\n\n  @@map(\"users\")\n}\n\nmodel Subscription {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  plan               SubscriptionPlan\n  status             SubscriptionStatus @default(PENDING)\n  currentPeriodStart DateTime\n  currentPeriodEnd   DateTime\n\n  stripeSubscriptionId String? @unique\n  stripePriceId        String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"subscriptions\")\n}\n\nmodel Score {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  score      Int // Stableford score 1-45\n  playedAt   DateTime\n  courseName String?\n  verified   Boolean  @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId, playedAt])\n  @@map(\"scores\")\n}\n\nmodel Charity {\n  id          String  @id @default(uuid())\n  name        String  @unique @db.VarChar(255)\n  description String  @db.Text\n  logoUrl     String? @db.VarChar(500)\n  website     String? @db.VarChar(500)\n  active      Boolean @default(true)\n\n  totalContributions Decimal @default(0) @db.Decimal(10, 2)\n\n  userCharities UserCharity[]\n  contributions CharityContribution[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"charities\")\n}\n\nmodel UserCharity {\n  id        String  @id @default(uuid())\n  userId    String  @unique\n  user      User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  charityId String\n  charity   Charity @relation(fields: [charityId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"user_charities\")\n}\n\nmodel CharityContribution {\n  id        String  @id @default(uuid())\n  charityId String\n  charity   Charity @relation(fields: [charityId], references: [id])\n\n  amount Decimal  @db.Decimal(10, 2)\n  source String // \"subscription\" or \"prize_pool\"\n  month  DateTime\n\n  createdAt DateTime @default(now())\n\n  @@map(\"charity_contributions\")\n}\n\nmodel Draw {\n  id     String     @id @default(uuid())\n  month  DateTime   @unique\n  status DrawStatus @default(UPCOMING)\n\n  winningNumbers Json? // 5 numbers stored as JSON array\n\n  prizePool         Decimal @default(0) @db.Decimal(10, 2)\n  charityAmount     Decimal @default(0) @db.Decimal(10, 2)\n  operationalAmount Decimal @default(0) @db.Decimal(10, 2)\n\n  fiveMatchPrize  Decimal @default(0) @db.Decimal(10, 2)\n  fourMatchPrize  Decimal @default(0) @db.Decimal(10, 2)\n  threeMatchPrize Decimal @default(0) @db.Decimal(10, 2)\n\n  drawDate DateTime?\n\n  entries DrawEntry[]\n  winners Winner[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"draws\")\n}\n\nmodel DrawEntry {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  drawId String\n  draw   Draw   @relation(fields: [drawId], references: [id], onDelete: Cascade)\n\n  numbers Json // 5 Stableford scores stored as JSON array\n\n  createdAt DateTime @default(now())\n\n  @@unique([userId, drawId])\n  @@index([drawId])\n  @@map(\"draw_entries\")\n}\n\nmodel Winner {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  drawId String\n  draw   Draw   @relation(fields: [drawId], references: [id], onDelete: Cascade)\n\n  matchCount     Int // 3, 4, or 5\n  matchedNumbers Json // Matched numbers stored as JSON array\n  prizeAmount    Decimal @db.Decimal(10, 2)\n\n  status WinnerStatus @default(PENDING_VERIFICATION)\n\n  proofUrl          String?   @db.VarChar(500)\n  verificationNotes String?   @db.Text\n  verifiedAt        DateTime?\n  verifiedBy        String?\n  paidAt            DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([drawId])\n  @@index([userId])\n  @@map(\"winners\")\n}\n\nmodel PrizePoolConfig {\n  id String @id @default(uuid())\n\n  charityPercentage     Int @default(10) // Minimum 10%\n  operationalPercentage Int @default(20)\n  fiveMatchPercentage   Int @default(40)\n  fourMatchPercentage   Int @default(20)\n  threeMatchPercentage  Int @default(10)\n\n  monthlyPrice Decimal @db.Decimal(10, 2)\n  yearlyPrice  Decimal @db.Decimal(10, 2)\n\n  active Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"prize_pool_configs\")\n}\n",
